class SecurePaymentStorage(private val context: Context) {
    private val KEYSTORE_PROVIDER = "AndroidKeyStore"
    private val KEY_ALIAS = "PaymentEncryptionKey"
    private val TRANSFORMATION = "AES/GCM/NoPadding"
    private val IV_SIZE = 12
    private val TAG_SIZE = 128
    
    private val preferences = context.getSharedPreferences("secure_payments", Context.MODE_PRIVATE)
    
    init {
