        }
    }
    
    @RequiresApi(Build.VERSION_CODES.M)
    private fun generateKeyIfNeeded() {
        val keyStore = KeyStore.getInstance(KEYSTORE_PROVIDER)
        keyStore.load(null)
        
        if (!keyStore.containsAlias(KEY_ALIAS)) {
            val keyGenerator = KeyGenerator.getInstance(
                KeyProperties.KEY_ALGORITHM_AES,
                KEYSTORE_PROVIDER
            )
            
            val keyGenParameterSpec = KeyGenParameterSpec.Builder(
                KEY_ALIAS,
                KeyProperties.PURPOSE_ENCRYPT or KeyProperties.PURPOSE_DECRYPT
            )
                .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
                .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
                .setRandomizedEncryptionRequired(false)
                .build()
            
            keyGenerator.init(keyGenParameterSpec)
            keyGenerator.generateKey()
        }
    }
    
    private fun getSecretKey(): SecretKey {
        return if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.M) {
            val keyStore = KeyStore.getInstance(KEYSTORE_PROVIDER)
            keyStore.load(null)
            keyStore.getKey(KEY_ALIAS, null) as SecretKey
        } else {
            val keyString = preferences.getString("legacy_key", null) ?: run {
                val newKey = ByteArray(32)
                SecureRandom().nextBytes(newKey)
                val encodedKey = Base64.encodeToString(newKey, Base64.NO_WRAP)
                preferences.edit().putString("legacy_key", encodedKey).apply()
                encodedKey
            }
            val keyBytes = Base64.decode(keyString, Base64.NO_WRAP)
            SecretKeySpec(keyBytes, "AES")
        }
    }
    
    fun encryptData(data: String): String {
        val cipher = Cipher.getInstance(TRANSFORMATION)
        val iv = ByteArray(IV_SIZE)
        SecureRandom().nextBytes(iv)
        val spec = GCMParameterSpec(TAG_SIZE, iv)
        
        cipher.init(Cipher.ENCRYPT_MODE, getSecretKey(), spec)
        val encrypted = cipher.doFinal(data.toByteArray(Charsets.UTF_8))
        
        val outputStream = ByteArrayOutputStream()
        outputStream.write(iv)
        outputStream.write(encrypted)
        
        return Base64.encodeToString(outputStream.toByteArray(), Base64.NO_WRAP)
    }
    
    fun decryptData(encryptedData: String): String {
        val decoded = Base64.decode(encryptedData, Base64.NO_WRAP)
        val iv = decoded.copyOfRange(0, IV_SIZE)
        val encrypted = decoded.copyOfRange(IV_SIZE, decoded.size)
        
        val cipher = Cipher.getInstance(TRANSFORMATION)
        val spec = GCMParameterSpec(TAG_SIZE, iv)
        
        cipher.init(Cipher.DECRYPT_MODE, getSecretKey(), spec)
        val decrypted = cipher.doFinal(encrypted)
        
        return String(decrypted, Charsets.UTF_8)
    }
    
