class PaymentProcessor(private val context: Context) {
    private val secureStorage = SecurePaymentStorage(context)
    private val transactionCache = ConcurrentHashMap<String, WalletTransaction>()
    
    fun validateCard(card: PaymentCard): Boolean {
        if (!isValidCardNumber(card.cardNumber)) return false
        if (!isValidExpiry(card.expiryMonth, card.expiryYear)) return false
        if (!isValidCVV(card.cvv)) return false
        if (card.holderName.isBlank()) return false
        
        return true
    }
    
    private fun isValidCardNumber(cardNumber: String): Boolean {
        val cleaned = cardNumber.replace("\\s+".toRegex(), "")
        if (cleaned.length !in 13..19) return false
        if (!cleaned.all { it.isDigit() }) return false
        
        var sum = 0
        var alternate = false
        for (i in cleaned.length - 1 downTo 0) {
            var digit = cleaned[i].toString().toInt()
            if (alternate) {
                digit *= 2
                if (digit > 9) digit -= 9
            }
            sum += digit
            alternate = !alternate
        }
        
        return sum % 10 == 0
    }
    
    private fun isValidExpiry(month: String, year: String): Boolean {
        val monthInt = month.toIntOrNull() ?: return false
        val yearInt = year.toIntOrNull() ?: return false
        
        if (monthInt !in 1..12) return false
        
        val currentYear = java.util.Calendar.getInstance().get(java.util.Calendar.YEAR) % 100
        val currentMonth = java.util.Calendar.getInstance().get(java.util.Calendar.MONTH) + 1
        
        if (yearInt < currentYear) return false
        if (yearInt == currentYear && monthInt < currentMonth) return false
        
        return true
    }
    
    private fun isValidCVV(cvv: String): Boolean {
        return cvv.length in 3..4 && cvv.all { it.isDigit() }
    }
    
    suspend fun processPayment(
        card: PaymentCard,
        amount: Double,
        currency: String,
        description: String
    ): PaymentResult = suspendCoroutine { continuation ->
        try {
            if (!validateCard(card)) {
                continuation.resume(PaymentResult.Failure("Invalid card details"))
                return@suspendCoroutine
            }
            
            if (amount <= 0) {
                continuation.resume(PaymentResult.Failure("Invalid amount"))
                return@suspendCoroutine
            }
            
            val transactionId = generateTransactionId()
            
            val transaction = WalletTransaction(
                id = transactionId,
                amount = amount,
                currency = currency,
                timestamp = System.currentTimeMillis(),
                status = TransactionStatus.PENDING,
                description = description
            )
            
            transactionCache[transactionId] = transaction
            
            android.os.Handler(android.os.Looper.getMainLooper()).postDelayed({
                val success = simulatePaymentProcessing()
                
                val updatedTransaction = transaction.copy(
                    status = if (success) TransactionStatus.COMPLETED else TransactionStatus.FAILED
                )
                
                transactionCache[transactionId] = updatedTransaction
                secureStorage.saveTransaction(updatedTransaction)
                
                if (success) {
                    continuation.resume(
                        PaymentResult.Success(
                            transactionId,
                            "Payment processed successfully"
                        )
                    )
                } else {
                    continuation.resume(PaymentResult.Failure("Payment processing failed"))
                }
            }, 2000)
            
        } catch (e: Exception) {
            Log.e("PaymentProcessor", "Payment error", e)
            continuation.resumeWithException(e)
        }
    }
    
    suspend fun processInAppPurchase(purchase: InAppPurchase): PaymentResult = 
        suspendCoroutine { continuation ->
            try {
                val transactionId = generateTransactionId()
                
                val transaction = WalletTransaction(
                    id = transactionId,
                    amount = purchase.price,
                    currency = purchase.currency,
                    timestamp = System.currentTimeMillis(),
                    status = TransactionStatus.PENDING,
                    description = "In-App Purchase: ${purchase.productId}"
                )
                
                transactionCache[transactionId] = transaction
                
                android.os.Handler(android.os.Looper.getMainLooper()).postDelayed({
                    val success = simulatePaymentProcessing()
                    
                    val updatedTransaction = transaction.copy(
                        status = if (success) TransactionStatus.COMPLETED else TransactionStatus.FAILED
                    )
                    
                    transactionCache[transactionId] = updatedTransaction
                    secureStorage.saveTransaction(updatedTransaction)
                    
                    if (success) {
                        continuation.resume(
                            PaymentResult.Success(
                                transactionId,
                                "In-app purchase completed"
                            )
                        )
                    } else {
                        continuation.resume(PaymentResult.Failure("In-app purchase failed"))
                    }
                }, 1500)
                
            } catch (e: Exception) {
                Log.e("PaymentProcessor", "In-app purchase error", e)
                continuation.resumeWithException(e)
            }
        }
    
    fun refundTransaction(transactionId: String): Boolean {
        val transaction = transactionCache[transactionId] 
            ?: secureStorage.getTransactionHistory().find { it.id == transactionId }
            ?: return false
        
        if (transaction.status != TransactionStatus.COMPLETED) return false
        
        val refundedTransaction = transaction.copy(status = TransactionStatus.REFUNDED)
        transactionCache[transactionId] = refundedTransaction
        secureStorage.saveTransaction(refundedTransaction)
        
        return true
    }
    
    fun getTransactionStatus(transactionId: String): TransactionStatus? {
        return transactionCache[transactionId]?.status 
            ?: secureStorage.getTransactionHistory().find { it.id == transactionId }?.status
    }
    
    fun getTransactionHistory(): List<WalletTransaction> {
        return secureStorage.getTransactionHistory()
    }
    
    private fun generateTransactionId(): String {
        val timestamp = System.currentTimeMillis()
        val random = SecureRandom().nextInt(100000)
        return "TXN${timestamp}${random}"
    }
    
    private fun simulatePaymentProcessing(): Boolean {
        return SecureRandom().nextInt(100) < 95
    }
}

class WalletManager(private val context: Context) {
    private val secureStorage = SecurePaymentStorage(context)
    private val preferences = context.getSharedPreferences("wallet", Context.MODE_PRIVATE)
    
    fun getBalance(): Double {
        return preferences.getFloat("balance", 0f).toDouble()
    }
    
    fun addFunds(amount: Double): Boolean {
        if (amount <= 0) return false
        
        val currentBalance = getBalance()
        val newBalance = currentBalance + amount
        
        preferences.edit().putFloat("balance", newBalance.toFloat()).apply()
        
        val transaction = WalletTransaction(
            id = "FUND${System.currentTimeMillis()}",
            amount = amount,
            currency = "USD",
            timestamp = System.currentTimeMillis(),
            status = TransactionStatus.COMPLETED,
            description = "Wallet fund added"
        )
        
        secureStorage.saveTransaction(transaction)
        return true
    }
    
    fun deductFunds(amount: Double): Boolean {
        val currentBalance = getBalance()
        if (amount <= 0 || amount > currentBalance) return false
        
        val newBalance = currentBalance - amount
        preferences.edit().putFloat("balance", newBalance.toFloat()).apply()
        
        val transaction = WalletTransaction(
            id = "DEDUCT${System.currentTimeMillis()}",
            amount = -amount,
            currency = "USD",
            timestamp = System.currentTimeMillis(),
            status = TransactionStatus.COMPLETED,
            description = "Wallet fund deducted"
        )
        
        secureStorage.saveTransaction(transaction)
        return true
    }
    
    fun transfer(recipientId: String, amount: Double): Boolean {
        if (!deductFunds(amount)) return false
        
        val transaction = WalletTransaction(
            id = "TRANSFER${System.currentTimeMillis()}",
            amount = -amount,
            currency = "USD",
            timestamp = System.currentTimeMillis(),
            status = TransactionStatus.COMPLETED,
            description = "Transfer to $recipientId"
        )
        
        secureStorage.saveTransaction(transaction)
        return true
    }
}

