class PaymentSecurityValidator {
    fun validateTransactionIntegrity(transaction: WalletTransaction): Boolean {
        if (transaction.amount <= 0) return false
        if (transaction.currency.isBlank()) return false
        if (transaction.id.isBlank()) return false
        
        return true
    }
    
    fun sanitizeInput(input: String): String {
        return input.replace(Regex("[^a-zA-Z0-9\\s-.]"), "")
    }
    
    fun maskCardNumber(cardNumber: String): String {
        val cleaned = cardNumber.replace("\\s+".toRegex(), "")
        if (cleaned.length < 4) return "****"
        
        val lastFour = cleaned.takeLast(4)
        val masked = "*".repeat(cleaned.length - 4)
        return "$masked$lastFour"
    }
    
    fun generateSecureToken(): String {
        val random = SecureRandom()
        val bytes = ByteArray(32)
        random.nextBytes(bytes)
        return Base64.encodeToString(bytes, Base64.NO_WRAP or Base64.NO_PADDING)
    }
}